@module clipboard  src=clipboard.lua  loc=490  sha=37ed80d  mode=chunk  self=clipboard
@deps ec, grid, tm, cm, currentRpb, getCtx, getLength, edit, aliases, fx

# Invariants & contracts
  @invariant  clipboard persists via REAPER ExtState under ('rdm','clipboard'), serialised by util.serialise  @ 4
  @invariant  clip rows are 0-relative to the clip's top (row=0 is first row of selection); paste re-bases against current cursor row  @ 5
  @invariant  single vs multi mode is decided by selected-col count: c1==c2 -> single, otherwise multi  @ 6
  @invariant  single.type ∈ { 'note', '7bit', 'pb' } — note/vel split decided at copy by region's part1  @ 7
  @invariant  multi.cols carry chanDelta from leftmost source channel; cursor's channel becomes the leftmost destination  @ 8
  @invariant  CLIP_RESERVED keys are stripped at copy; CLIP_ARTIFACTS (row/endRow) are stripped at paste; everything else (including custom metadata) round-trips  @ 9
  @invariant  velEvent is the only collector that synthesises a clip event rather than cloning the source — vel-mode pastes must not carry note metadata onto cc destinations  @ 10

# Imports
  @require util = 'util'  @ 11

