  @state edit = deps.edit  @ 43   -- leaf-edit facade: routes add/delete/assign to gm or tm by cell kind
  @state aliases = deps.aliases  @ 44   -- (cells) -> bool: refuse a paste whose footprint aliases one group
  @state fx = deps.fx  @ 45   -- { gather(r1,r2,c1,c2,anchorChan), paste(list) }: fx regions ride the clip
  @state clipboard = {}  @ 473

# Private functions
  @fn save(clip)  @ 47-49
  @fn load()  @ 51-55
  @fn collect()  @ 58-168
      @contract  nil if the resolved selection is empty; single-col → { mode='single', type, ... }; multi-col → { mode='multi', cols=[...] }.  @ 57
  @fn refusePaste(chan, evType, lane, cc, startRow, numRows)  @ 173-180
      -- One footprint cell per destination row, fed to aliases() so a paste covering
      -- >=2 instances of one group is refused in global mode (decision 5). Mirrors the
      -- shiftEvents gate; see design/group-aware-editing.md § Injectivity predicate.
  @fn pasteVelocities(events, dstCol, startppq, endppq)  @ 183-224
      @contract  carry-forward over note-ons in region (clip val updates currentVel, then writes onto next note-ons); pass 2 may emit PA events on sustain rows when cm.polyAftertouch is set  @ 182
  @fn pasteSingle(clip)  @ 227-317
      @contract  dispatches by (clip.type, dstCol.type, cursorPart): note->note(pitch), 7bit->note(vel) via pasteVelocities, pb->pb, 7bit->cc/at/pc; mismatched combos silently no-op.  @ 226
  @fn pasteMulti(clip)  @ 320-438
      @contract  resolves each clip col against cursor's chan via chanDelta; out-of-range channels and missing destinations skip silently; bails entirely if startType=='note' but cursor isn't on a note col.  @ 319
  @fn pasteClip(clip)  @ 440-445
  @fn trimTop(clip, trim)  @ 449-469
      -- A note whose start row falls within the trimmed band is dropped entirely.
      @contract  mutates clip in place; survives both modes; used by duplicate-up at row 0 to keep selection-following behaviour cumulative  @ 447

